   131	void e1_bearer_context_setup(const e1ap_bearer_setup_req_t *req)
   132	{
   133	  bool need_ue_id_mgmt = e1_used();
   134	
   135	  /* mirror the CU-CP UE ID for CU-UP */
   136	  uint32_t cu_up_ue_id = req->gNB_cu_cp_ue_id;
   137	  f1_ue_data_t ued = {.secondary_ue = req->gNB_cu_cp_ue_id};
   138	  if (need_ue_id_mgmt) {
   139	    cu_add_f1_ue_data(cu_up_ue_id, &ued);
   140	    LOG_I(E1AP, "adding UE with CU-CP UE ID %d and CU-UP UE ID %d\n", req->gNB_cu_cp_ue_id, cu_up_ue_id);
   141	  }
   142	
   143	  instance_t n3inst = get_n3_gtp_instance();
   144	  instance_t f1inst = get_f1_gtp_instance();
   145	
   146	  e1ap_bearer_setup_resp_t resp = {
   147	    .gNB_cu_cp_ue_id = req->gNB_cu_cp_ue_id,
   148	    .gNB_cu_up_ue_id = cu_up_ue_id,
   149	  };
   150	  resp.numPDUSessions = req->numPDUSessions;
   151	  for (int i = 0; i < resp.numPDUSessions; ++i) {
   152	    pdu_session_setup_t *resp_pdu = resp.pduSession + i;
   153	    const pdu_session_to_setup_t *req_pdu = req->pduSession + i;
   154	    resp_pdu->id = req_pdu->sessionId;
   155	
   156	    AssertFatal(req_pdu->numDRB2Modify == 0, "DRB modification not implemented\n");
   157	    AssertFatal(req_pdu->numDRB2Setup == 1, "can only handle one DRB per PDU session\n");
   158	    resp_pdu->numDRBSetup = req_pdu->numDRB2Setup;
   159	    const DRB_nGRAN_to_setup_t *req_drb = &req_pdu->DRBnGRanList[0];
   160	    AssertFatal(req_drb->numQosFlow2Setup == 1, "can only handle one QoS Flow per DRB\n");
   161	    DRB_nGRAN_setup_t *resp_drb = &resp_pdu->DRBnGRanList[0];
   162	    resp_drb->id = req_drb->id;
   163	    resp_drb->numQosFlowSetup = req_drb->numQosFlow2Setup;
   164	    for (int k = 0; k < resp_drb->numQosFlowSetup; k++) {
   165	      const qos_flow_to_setup_t *qosflow2Setup = &req_drb->qosFlows[k];
   166	      qos_flow_setup_t *qosflowSetup = &resp_drb->qosFlows[k];
   167	      qosflowSetup->qfi = qosflow2Setup->qfi;
   168	    }
   169	
   170	    // GTP tunnel for N3/to core
   171	    gtpv1u_gnb_create_tunnel_resp_t resp_n3 = {0};
   172	    int qfi = req_drb->qosFlows[0].qfi;
   173	    int ret = drb_gtpu_create(n3inst,
   174	                              cu_up_ue_id,
   175	                              req_drb->id,
   176	                              req_pdu->sessionId,
   177	                              qfi,
   178	                              req_pdu->tlAddress,
   179	                              req_pdu->teId,
   180	                              nr_pdcp_data_req_drb,
   181	                              sdap_data_req,
   182	                              &resp_n3);
   183	    AssertFatal(ret >= 0, "Unable to create GTP Tunnel for NG-U\n");
   184	    AssertFatal(resp_n3.num_tunnels == req_pdu->numDRB2Setup, "could not create all tunnels\n");
   185	    resp_pdu->teId = resp_n3.gnb_NGu_teid[0];
   186	    memcpy(&resp_pdu->tlAddress, &resp_n3.gnb_addr.buffer, 4);
   187	
   188	    // create PDCP bearers. This will also create SDAP bearers
   189	    NR_DRB_ToAddModList_t DRB_configList = {0};
   190	    fill_DRB_configList_e1(&DRB_configList, req_pdu);
   191	    nr_pdcp_entity_security_keys_and_algos_t security_parameters;
   192	    security_parameters.ciphering_algorithm = req->cipheringAlgorithm;
   193	    security_parameters.integrity_algorithm = req->integrityProtectionAlgorithm;
   194	    memcpy(security_parameters.ciphering_key, req->encryptionKey, NR_K_KEY_SIZE);
   195	    memcpy(security_parameters.integrity_key, req->integrityProtectionKey, NR_K_KEY_SIZE);
   196	    nr_pdcp_add_drbs(true, // set this to notify PDCP that his not UE
   197	                     cu_up_ue_id,
   198	                     &DRB_configList,
   199	                     &security_parameters);
   200	    ASN_STRUCT_RESET(asn_DEF_NR_DRB_ToAddModList, &DRB_configList.list);

void e1_bearer_context_modif(const e1ap_bearer_mod_req_t *req)
{
  AssertFatal(req->numPDUSessionsMod > 0, "need at least one PDU session to modify\n");

  e1ap_bearer_modif_resp_t modif = {
      .gNB_cu_cp_ue_id = req->gNB_cu_cp_ue_id,
      .gNB_cu_up_ue_id = req->gNB_cu_up_ue_id,
      .numPDUSessionsMod = req->numPDUSessionsMod,
  };

  instance_t f1inst = get_f1_gtp_instance();

  /* PDU Session Resource To Modify List (see 9.3.3.11 of TS 38.463) */
  for (int i = 0; i < req->numPDUSessionsMod; i++) {
    DevAssert(req->pduSessionMod[i].sessionId > 0);
    LOG_I(E1AP,
          "UE %d: updating PDU session ID %ld (%ld bearers)\n",
          req->gNB_cu_up_ue_id,
          req->pduSessionMod[i].sessionId,
          req->pduSessionMod[i].numDRB2Modify);
    modif.pduSessionMod[i].id = req->pduSessionMod[i].sessionId;
    modif.pduSessionMod[i].numDRBModified = req->pduSessionMod[i].numDRB2Modify;
    /* DRBs to modify */
    for (int j = 0; j < req->pduSessionMod[i].numDRB2Modify; j++) {
      const DRB_nGRAN_to_mod_t *to_modif = &req->pduSessionMod[i].DRBnGRanModList[j];
      DRB_nGRAN_modified_t *modified = &modif.pduSessionMod[i].DRBnGRanModList[j];
      modified->id = to_modif->id;

      if (to_modif->pdcp_config.pDCP_Reestablishment) {
        nr_pdcp_entity_security_keys_and_algos_t security_parameters;
        security_parameters.ciphering_algorithm = req->cipheringAlgorithm;
        security_parameters.integrity_algorithm = req->integrityProtectionAlgorithm;
        memcpy(security_parameters.ciphering_key, req->encryptionKey, NR_K_KEY_SIZE);
        memcpy(security_parameters.integrity_key, req->integrityProtectionKey, NR_K_KEY_SIZE);
        nr_pdcp_reestablishment(req->gNB_cu_up_ue_id,
                                to_modif->id,
                                false,
                                &security_parameters);
      }

      if (f1inst < 0) // no F1-U?
        continue; // nothing to do

      /* Loop through DL UP Transport Layer params list
       * and update GTP tunnel outgoing addr and TEID */
      for (int k = 0; k < to_modif->numDlUpParam; k++) {
        in_addr_t addr = to_modif->DlUpParamList[k].tlAddress;
        GtpuUpdateTunnelOutgoingAddressAndTeid(f1inst, req->gNB_cu_cp_ue_id, to_modif->id, addr, to_modif->DlUpParamList[k].teId);

